import { Modal, Spin, Descriptions, Typography } from "antd";
import { useEffect, useState } from "react";
import PropTypes from 'prop-types';
import dayjs from 'dayjs';
import Notice from "src/components/Notice";
import ButtonCustom from "src/components/MyButton/Button";
import ApprovedLeaveApi from "src/services/ApprovedLeaveService";
import { getListComboByKey } from "src/lib/utils";

const { Text } = Typography;
const ModalApprovedLeaveAssociation = ({
  open,
  onCancel,
  onOk,
  selectedRecord,
  onApprove,
  onReject,
  allSystemKeys,
}) => {
  const [detailLoading, setDetailLoading] = useState(false);
  const [detailData, setDetailData] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);

  // const memberTypeMap = {
  //   "Cá nhân": 1,
  //   "Doanh nghiệp": 2,
  // };

  const formatDisplayDate = (dateString) => {
    if (!dateString) return 'N/A';
    try {
      const dateObj = dayjs(dateString);
      if (dateObj.isValid()) {
        return dateObj.format('DD/MM/YYYY');
      }
    } catch (e) {
      console.warn("Could not format date for display:", dateString, e);
    }
    return dateString;
  };
  useEffect(() => {
    const fetchDetailData = async () => {
      if (!open || !selectedRecord || !selectedRecord.ID || !selectedRecord.MemberType) {
        setDetailData(null);
        return;
      }

      setDetailLoading(true);
      try {
       // Lấy danh sách MemberType từ allSystemKeys
      const memberTypeOptions = getListComboByKey("MEMBER_TYPE", allSystemKeys);

      // Chuyển đổi selectedRecord.MemberType (chuỗi: "Cá nhân") thành CodeValue (số: 1) cho API
      const memberTypeForApi = memberTypeOptions.find(
        opt => opt.Description === selectedRecord.MemberType
      )?.CodeValue; // Lấy CodeValue dưới dạng string

        if (memberTypeForApi === undefined) {
          console.warn("Invalid MemberType for API:", selectedRecord.MemberType);
          Notice({ msg: "Loại thành viên không hợp lệ.", isSuccess: false });
          setDetailLoading(false);
          return;
        }

        const params = {
          requestId: selectedRecord.ID,
          memberType: parseInt(memberTypeForApi, 10), // Đảm bảo là số nguyên
        };

        const response = await ApprovedLeaveApi.GetLeaveMemberDetail(params);

        if (response && response.isOk && response.Object) {
          setDetailData({
            ...response.Object,
            ButtonShow: selectedRecord.ButtonShow

          });
        } else {
          Notice({ msg: response?.Message || "Không thể tải dữ liệu chi tiết.", isSuccess: false });
          setDetailData(null);
        }
      } catch (error) {
        console.error("Lỗi khi tải dữ liệu chi tiết:", error);
        Notice({ msg: "Lỗi kết nối khi tải dữ liệu chi tiết.", isSuccess: false });
        setDetailData(null);
      } finally {
        setDetailLoading(false);
      }
    };

    fetchDetailData();
  }, [open, selectedRecord,allSystemKeys]);

  // THÊM HÀM NÀY ĐỂ LẤY TÊN HIỂN THỊ CỦA LOẠI THÀNH VIÊN
  const getMemberTypeDisplayName = (memberTypeCodeValue) => {
    if (!allSystemKeys || allSystemKeys.length === 0) return memberTypeCodeValue; // Fallback nếu chưa tải data
    const memberTypeOptions = getListComboByKey("MEMBER_TYPE", allSystemKeys);
    return memberTypeOptions.find(opt => parseInt(opt.CodeValue, 10) === memberTypeCodeValue)?.Description || memberTypeCodeValue;
  };

  const displayMemberType = getMemberTypeDisplayName(detailData?.MemberType);


  const modalTitle = displayMemberType === 'Doanh nghiệp'
    ? "Chi Tiết Đơn Xin Rút Của Tổ Chức"
    : "Chi Tiết Đơn Xin Rút Của Cá Nhân";

  const handleApproveClick = () => {
    setActionLoading(true);
    onApprove(selectedRecord, () => {
      setActionLoading(false);
      onCancel();
      if (onOk) onOk();
    });
  };

  const handleRejectClick = () => {
    setActionLoading(true);
    onReject(selectedRecord, () => {
      setActionLoading(false);
      onCancel();
      if (onOk) onOk();
    });
  };
  const renderFooter = () => (
    <div style={{ display: 'flex', justifyContent: 'center', gap: '12px' }}>
      {detailData?.ButtonShow?.IsApprove && (
        <ButtonCustom
          type="primary"
          className="btn-hover-shadow"
          onClick={() => handleApproveClick('approve')}
          loading={actionLoading}
        >
          Chấp Nhận
        </ButtonCustom>
      )}
      {detailData?.ButtonShow?.IsReject && (
        <ButtonCustom
          type="default"
          onClick={() => handleRejectClick('reject')}
          loading={actionLoading}
        >
          Từ Chối
        </ButtonCustom>
      )}
      <ButtonCustom
        type="default"
        onClick={onCancel} // Nút "Quay Lại" sẽ gọi onCancel để đóng modal và về danh sách
      >
        Quay Lại
      </ButtonCustom>
    </div>
  );

  return (
    <Modal
      title={modalTitle}
      open={open}
      width={700}
      onCancel={onCancel}
      footer={renderFooter()}
      destroyOnClose={true}
    >
      <Spin spinning={detailLoading || actionLoading}>
        {detailData ? (
          <Descriptions bordered column={1} size="middle">
            {displayMemberType === 'Cá nhân' && (
              <>
                <Descriptions.Item label="Số CCCD">
                  <Text>{detailData.Identification || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Tên Hội Viên">
                  <Text>{detailData.FullName || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Số Điện Thoại">
                  <Text>{detailData.PhoneNumber || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Email">
                  <Text>{detailData.Email || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Đơn Vị">
                  <Text>{detailData.AccountName || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Ngày Làm Đơn">
                  <Text>{formatDisplayDate(detailData.CreateDate)}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Lý Do">
                  <Text>{detailData.Reason || 'N/A'}</Text>
                </Descriptions.Item>
                {detailData.ApprovedBy && (
                  <Descriptions.Item label="Người Duyệt">
                    <Text>{detailData.ApprovedBy}</Text>
                  </Descriptions.Item>
                )}
                {detailData.ApprovedDate && (
                  <Descriptions.Item label="Ngày Duyệt">
                    <Text>{formatDisplayDate(detailData.ApprovedDate)}</Text>
                  </Descriptions.Item>
                )}
                {detailData.RejectReason && (
                  <Descriptions.Item label="Lý Do Từ Chối">
                    <Text>{detailData.RejectReason}</Text>
                  </Descriptions.Item>
                )}
              </>
            )}

            {displayMemberType === 'Doanh nghiệp' && (
              <>
                <Descriptions.Item label="Mã Số Thuế">
                  <Text>{detailData.TaxCode || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Tên Tổ Chức">
                  <Text>{detailData.OrganizationName || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Tên Người Đại Diện">
                  <Text>{detailData.RepresentativeName || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Địa Chỉ">
                  <Text>{detailData.Address || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Chức Vụ">
                  <Text>{detailData.RepresentativePosition || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Email">
                  <Text>{detailData.Email || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Số Điện Thoại">
                  <Text>{detailData.PhoneNumber || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Đơn Vị">
                  <Text>{detailData.AccountName || 'N/A'}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Ngày Làm Đơn">
                  <Text>{formatDisplayDate(detailData.CreateDate)}</Text>
                </Descriptions.Item>
                <Descriptions.Item label="Lý Do">
                  <Text>{detailData.Reason || 'N/A'}</Text>
                </Descriptions.Item>
              </>
            )}
          </Descriptions>
        ) : (
          <p style={{ textAlign: 'center', padding: '20px' }}>Không có dữ liệu chi tiết để hiển thị.</p>
        )}
      </Spin>
    </Modal>
  );
};

ModalApprovedLeaveAssociation.propTypes = {
  open: PropTypes.bool.isRequired,
  onCancel: PropTypes.func.isRequired,
  onOk: PropTypes.func,
  onApprove: PropTypes.func.isRequired,
  onReject: PropTypes.func.isRequired,
  allSystemKeys: PropTypes.array.isRequired,
  selectedRecord: PropTypes.shape({
    Identification: PropTypes.string,
    ID: PropTypes.string,
    TaxCode: PropTypes.string,
    FullName: PropTypes.string,
    OrganizationName: PropTypes.string,
    RepresentativePosition: PropTypes.string,
    Address: PropTypes.string,
    MemberType: PropTypes.oneOfType([PropTypes.string, PropTypes.number]),
    CreateDate: PropTypes.string,
    Reason: PropTypes.string,
    PhoneNumber: PropTypes.string,
    Email: PropTypes.string,
    AccountName: PropTypes.string,
    RepresentativeName: PropTypes.string,
    Status: PropTypes.oneOf([1, 2, 3, 'Chờ duyệt', 'Đã duyệt', 'Từ chối']),
    ButtonShow: PropTypes.shape({
      IsVisitTab: PropTypes.bool,
      IsDetail: PropTypes.bool,
      IsApprove: PropTypes.bool,
      IsReject: PropTypes.bool,
    }).isRequired,
    
  }),
}

export default ModalApprovedLeaveAssociation;