import http from "../01_axios"
import {
    apiGetListLeaveRequest,
    apiRejectLeaveRequest,
    apiApproveLeaveRequest,
    apiGetLeaveMemberDetail
} from "./urls"
const GetListLeaveRequest = params =>    http.get(apiGetListLeaveRequest, { params: params });
const GetLeaveMemberDetail = params =>    http.get(apiGetLeaveMemberDetail, { params: params });
const RejectLeaveRequest = body =>    http.post(apiRejectLeaveRequest, body);
const ApproveLeaveRequest = body =>    http.post(apiApproveLeaveRequest, body);

const ApprovedLeaveApi = {
    GetListLeaveRequest,
    RejectLeaveRequest,
    ApproveLeaveRequest,
    GetLeaveMemberDetail
}
export default ApprovedLeaveApi