import { Col, DatePicker, Row, Select } from "antd"
import dayjs from "dayjs"
import { useCallback, useEffect, useState } from "react"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import TitleCustom from "src/components/TitleCustom"
import { useBadgeCounts } from "src/hooks/useBadgeCounts"
import { getListComboByKey } from "src/lib/utils"
import ApprovedLeaveApi from "src/services/ApprovedLeaveService"
import CommonService from "src/services/CommonService"
import ModalApprovedLeaveAssociation from "./modal/ModalApprovedLeaveAssociation.jsx"

const ApprovedLeaveAssociation = () => {
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState({ data: [], total: 0 })
  const [selectedRowKeys, setSelectedRowKeys] = useState([])
  const [isDetailModalVisible, setIsDetailModalVisible] = useState(false)
  const [selectedRecordDetail, setSelectedRecordDetail] = useState(null)
  const [allSystemKeys, setAllSystemKeys] = useState([])
  const [isSystemKeysLoaded, setIsSystemKeysLoaded] = useState(false) // ✅ Thêm flag kiểm soát

  const [filters, setFilters] = useState({
    textSearch: "",
    taxCodeSearch: "",
    fromDate: null,
    toDate: null,
    selectedMemberType: "Tất Cả",
    selectedStatus: "Chờ duyệt",
    pagination: { PageSize: 20, CurrentPage: 1 },
  })

  const {
    textSearch,
    taxCodeSearch,
    fromDate,
    toDate,
    selectedMemberType,
    selectedStatus,
    pagination,
  } = filters

  const dateRange = fromDate && toDate ? [dayjs(fromDate), dayjs(toDate)] : []

  const rowSelection = {
    selectedRowKeys,
    onChange: selectedKeys => {
      setSelectedRowKeys(selectedKeys)
    },
    onSelectAll: selected => {
      if (selected) {
        const selectableKeys = listData.data
          .filter(record => record.Status === "Chờ duyệt")
          .map(record => record.ID)
        setSelectedRowKeys(selectableKeys)
      } else {
        setSelectedRowKeys([])
      }
    },
    getCheckboxProps: record => {
      const statusOptions = getListComboByKey("USER_STATUS", allSystemKeys)
      const currentStatusDesc =
        statusOptions.find(opt => parseInt(opt.CodeValue, 10) === record.Status)
          ?.Description || record.Status
      return {
        disabled:
          currentStatusDesc === "Đã duyệt" || currentStatusDesc === "Từ chối",
        name: record.ID,
      }
    },
  }

  const columns = [
    {
      title: "STT",
      key: "Index",
      width: 50,
      align: "center",
      render: (val, record, idx) => {
        return (
          <div className="text-center">
            {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
          </div>
        )
      },
    },
    {
      width: 150,
      title: (
        <>
          <MainTableHeader>Số CCCD</MainTableHeader>
          <SubTableHeader>Mã Số Thuế</SubTableHeader>
        </>
      ),
      dataIndex: "Identity",
      key: "Identity",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{record?.Identity}</MainTableData>
          {/* <SubTableData>{record?.TaxCode || "N/A"}</SubTableData> */}
        </>
      ),
    },
    {
      width: 200,
      title: (
        <>
          <MainTableHeader>Tên Người</MainTableHeader>
          <SubTableHeader>Loại Thành Viên</SubTableHeader>
        </>
      ),
      dataIndex: "Name",
      key: "Name",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{record?.Name || "-"}</MainTableData>
          <SubTableData>
            {getListComboByKey("MEMBER_TYPE", allSystemKeys).find(
              opt => parseInt(opt.CodeValue, 10) === record?.MemberType,
            )?.Description ||
              record?.MemberType ||
              "-"}
          </SubTableData>
        </>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Email</MainTableHeader>
          <SubTableHeader>Số Điện Thoại</SubTableHeader>
        </>
      ),
      dataIndex: "Email",
      key: "Email",
      align: "center",
      render: (val, record) => (
        <>
          <MainTableData>{record?.Email || "-"}</MainTableData>
          <SubTableData>{record?.PhoneNumber || "-"}</SubTableData>
        </>
      ),
    },
    {
      title: "Ngày Làm Đơn",
      dataIndex: "CreateDate",
      key: "CreateDate",
      width: 100,
      align: "center",
      render: text => {
        let displayDate = text
        try {
          const dateObj = dayjs(text)
          if (dateObj.isValid()) {
            displayDate = dateObj.format("DD/MM/YYYY")
          }
        } catch (e) {
          console.warn("Could not format CreateDate for display:", text, e)
        }

        return (
          <div>
            <div title={text}>{displayDate}</div>
          </div>
        )
      },
    },
    {
      title: "Lý Do",
      dataIndex: "Reason",
      key: "Reason",
      align: "center",
      width: 400,
      render: text => (
        <div>
          <div title={text}>{text}</div>
        </div>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "StatusAction",
      align: "center",
      width: 165,
      render: (val, record) => {
        let statusStyle = {}

        const statusOptions = getListComboByKey("USER_STATUS", allSystemKeys)
        const currentStatusDesc =
          statusOptions.find(
            opt => parseInt(opt.CodeValue, 10) === record.Status,
          )?.Description || record.Status

        if (currentStatusDesc === "Chờ duyệt") {
          statusStyle = { color: "#FF8C00", fontWeight: "bold" }
        } else if (currentStatusDesc === "Đã duyệt") {
          statusStyle = { color: "#008000", fontWeight: "bold" }
        } else if (currentStatusDesc === "Từ chối") {
          statusStyle = { color: "#FF0000", fontWeight: "bold" }
        }

        const detailButtonBgColor = "#E6F7FF"
        const approveButtonBgColor = "#F6FFED"
        const rejectButtonBgColor = "#FFF0F0"

        return (
          <div className="text-center">
            <div
              className="max-line2"
              title={currentStatusDesc}
              style={statusStyle}
            >
              {currentStatusDesc}
            </div>

            <FloatActionWrapper size="small" className="float-action__wrapper">
              {record?.ButtonShow?.IsDetail && (
                <ButtonCircle
                  className="button-circle"
                  title="Xem chi tiết"
                  iconName="eye"
                  style={{
                    background: detailButtonBgColor,
                    boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                  }}
                  onClick={e => {
                    e.stopPropagation()
                    handleAction("detail", record)
                  }}
                />
              )}

              {currentStatusDesc === "Chờ duyệt" &&
                record?.ButtonShow?.IsApprove && (
                  <>
                    <ButtonCircle
                      className="button-circle"
                      title="Chấp nhận"
                      iconName="check-circle"
                      style={{
                        background: approveButtonBgColor,
                        boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                      }}
                      onClick={e => {
                        e.stopPropagation()
                        handleApprove(record)
                      }}
                    />

                    <ButtonCircle
                      className="button-circle"
                      title="Từ chối"
                      iconName="cancel"
                      style={{
                        background: rejectButtonBgColor,
                        boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                      }}
                      onClick={e => {
                        e.stopPropagation()
                        handleReject(record)
                      }}
                    />
                  </>
                )}
            </FloatActionWrapper>
          </div>
        )
      },
    },
  ]
  const { badgeCounts } = useBadgeCounts()
  const pendingRequestsCount = badgeCounts.leaveRequest || 0

  const fetchSystemKeys = useCallback(async () => {
    try {
      const response = await CommonService.getSystemKey()
      if (response && response.isOk && Array.isArray(response.Object)) {
        setAllSystemKeys(response.Object)
        setIsSystemKeysLoaded(true)
      } else {
        console.warn(
          "API response for all SystemKeys is invalid or empty:",
          response,
        )
        setAllSystemKeys([])
        setIsSystemKeysLoaded(true)
      }
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu cấu hình SystemKey:", error)
      Notice({
        msg: "Không thể tải dữ liệu cấu hình. Vui lòng thử lại.",
        isSuccess: false,
      })
      setAllSystemKeys([])
      setIsSystemKeysLoaded(true) // ✅ Vẫn đánh dấu hoàn thành dù lỗi
    }
  }, [])

  useEffect(() => {
    fetchSystemKeys()
  }, [fetchSystemKeys])

  const memberTypeMap = useCallback(() => {
    const options = getListComboByKey("MEMBER_TYPE", allSystemKeys)
    const map = { "Tất Cả": 0 }
    options.forEach(item => {
      map[item.Description] = parseInt(item.CodeValue, 10)
    })
    return map
  }, [allSystemKeys])

  const statusMap = useCallback(() => {
    const options = getListComboByKey("USER_STATUS", allSystemKeys)
    const map = { "Tất Cả": 0 }
    options.forEach(item => {
      map[item.Description] = parseInt(item.CodeValue, 10)
    })
    return map
  }, [allSystemKeys])

  const handleApprove = (record = null, callback = () => {}) => {
    const isBulkAction = record === null
    const itemsToProcess = isBulkAction ? selectedRowKeys : [record?.ID]

    if (itemsToProcess.length === 0) {
      Notice({
        msg: "Bạn chưa chọn mục nào để chấp nhận.",
        isSuccess: false,
      })
      callback()
      return
    }

    const confirmationTitle = isBulkAction
      ? `Bạn có chắc muốn duyệt <Strong>${itemsToProcess.length}</Strong> đơn đã chọn không?`
      : `Bạn có chắc muốn duyệt đơn của <Strong>${record?.Name}</Strong> không?`

    CB1({
      title: confirmationTitle,
      okText: "Đồng ý",
      onOk: async close => {
        try {
          setLoading(true)
          const response = await ApprovedLeaveApi.ApproveLeaveRequest(
            itemsToProcess,
          )
          if (response && response.isOk) {
            const msg = isBulkAction
              ? `Đã duyệt ${itemsToProcess.length} đơn thành công!`
              : `Đã duyệt đơn của ${record?.Name} thành công!`
            Notice({ msg: msg, isSuccess: true })
            setSelectedRowKeys([])
            loadData()
            callback()
          } else {
            Notice({
              msg:
                response?.Object ||
                response?.Message ||
                "Đã xảy ra lỗi khi duyệt đơn.",
              isSuccess: false,
            })
          }
        } catch (error) {
          console.error("Lỗi khi gọi API duyệt:", error)
          Notice({
            msg: "Lỗi kết nối hoặc server khi duyệt đơn.",
            isSuccess: false,
          })
        } finally {
          setLoading(false)
          close()
          callback()
        }
      },
      onCancel: close => {
        close()
        callback()
      },
    })
  }

  const handleReject = (record = null, callback = () => {}) => {
    const isBulkAction = record === null
    const itemsToProcess = isBulkAction ? selectedRowKeys : [record?.ID]

    if (itemsToProcess.length === 0) {
      Notice({
        msg: "Bạn chưa chọn mục nào để từ chối.",
        isSuccess: false,
      })
      callback()
      return
    }

    const confirmationTitle = isBulkAction
      ? `Bạn có chắc muốn từ chối <Strong>${itemsToProcess.length}</Strong> đơn đã chọn không?`
      : `Bạn có chắc muốn từ chối đơn của <Strong>${record?.Name}</Strong> không?`

    CB1({
      title: confirmationTitle,
      okText: "Từ chối",
      onOk: async close => {
        try {
          setLoading(true)
          const response = await ApprovedLeaveApi.RejectLeaveRequest(
            itemsToProcess,
          )
          if (response && response.isOk) {
            const msg = isBulkAction
              ? `Đã từ chối ${itemsToProcess.length} đơn thành công!`
              : `Đã từ chối đơn của ${record?.Name} thành công!`
            Notice({ msg: msg, isSuccess: true })
            setSelectedRowKeys([])
            loadData()
            callback()
          } else {
            Notice({
              msg:
                response?.Object ||
                response?.Message ||
                "Đã xảy ra lỗi khi từ chối đơn.",
              isSuccess: false,
            })
          }
        } catch (error) {
          console.error("Lỗi khi gọi API từ chối:", error)
          Notice({
            msg: "Lỗi kết nối hoặc server khi từ chối đơn.",
            isSuccess: false,
          })
        } finally {
          setLoading(false)
          close()
          callback()
        }
      },
      onCancel: close => {
        close()
        callback()
      },
    })
  }

  const handleAction = (actionType, record = null, callback = () => {}) => {
    if (actionType === "detail") {
      setSelectedRecordDetail(record)
      setIsDetailModalVisible(true)
      callback()
      return
    }
  }

  const handleTableChange = (page, pageSize) => {
    setFilters(prevFilters => ({
      ...prevFilters,
      pagination: { CurrentPage: page, PageSize: pageSize },
    }))
  }

  const handleDateRangeChange = dates => {
    setFilters(prevFilters => ({
      ...prevFilters,
      fromDate: dates ? dates[0] : null,
      toDate: dates ? dates[1] : null,
      pagination: { ...prevFilters.pagination, CurrentPage: 1 },
    }))
  }

  const handleMemberTypeChange = value => {
    setFilters(prevFilters => ({
      ...prevFilters,
      selectedMemberType: value,
      pagination: { ...prevFilters.pagination, CurrentPage: 1 },
    }))
  }

  const handleStatusChange = value => {
    setFilters(prevFilters => ({
      ...prevFilters,
      selectedStatus: value,
      pagination: { ...prevFilters.pagination, CurrentPage: 1 },
    }))
  }

  const handleTextSearchChange = e => {
    setFilters(prevFilters => ({
      ...prevFilters,
      textSearch: e.target.value,
      pagination: { ...prevFilters.pagination, CurrentPage: 1 },
    }))
  }

  const handleTaxCodeSearchChange = e => {
    setFilters(prevFilters => ({
      ...prevFilters,
      taxCodeSearch: e.target.value,
      pagination: { ...prevFilters.pagination, CurrentPage: 1 },
    }))
  }

  const handleRowClick = record => {
    handleAction("detail", record)
  }

  const handleCloseDetailModal = () => {
    setIsDetailModalVisible(false)
    setSelectedRecordDetail(null)
  }

  // ✅ Tối ưu hóa loadData: Chỉ gọi khi SystemKeys đã tải xong
  const loadData = useCallback(async () => {
    if (!isSystemKeysLoaded) return // ✅ Chỉ chạy khi SystemKeys đã tải xong

    setLoading(true)
    setSelectedRowKeys([])

    try {
      const params = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        ToDate: toDate ? toDate.endOf("day").format("YYYY/MM/DD HH:mm:ss") : "",
      }

      const currentMemberTypeMap = memberTypeMap()
      const memberTypeValue = currentMemberTypeMap[selectedMemberType]
      if (memberTypeValue !== 0) {
        params.MemberType = memberTypeValue
      }

      const currentStatusMap = statusMap()
      const statusValue = currentStatusMap[selectedStatus]
      if (statusValue !== 0) {
        params.Status = statusValue
      }

      if (fromDate) {
        params.FromDate = fromDate.startOf("day").format("YYYY/MM/DD HH:mm:ss")
      }
      if (textSearch) {
        params.TextSearch = textSearch
      }
      if (taxCodeSearch) {
        params.TaxCodeSearch = taxCodeSearch
      }

      console.log("Parameters sent to API:", params)
      const response = await ApprovedLeaveApi.GetListLeaveRequest(params)

      if (response && response.isOk && response.Object) {
        const apiData = response.Object.ListUserRequest
        const apiTotal = response.Object.Total

        if (Array.isArray(apiData)) {
          const dataForTable = apiData.map(item => ({
            ...item,
          }))

          setListData({
            data: dataForTable,
            total: apiTotal || 0,
          })
          console.log(
            "Data loaded successfully. Total items:",
            apiTotal,
            "Data for table:",
            dataForTable,
          )
        } else {
          console.warn("API response ListUserRequest is not an array:", apiData)
          setListData({
            data: [],
            total: 0,
          })
        }
      } else {
        console.warn(
          "API response is missing Object or is not successful (isOk is false):",
          response,
        )
        setListData({
          data: [],
          total: 0,
        })
      }
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu từ API:", error)
      Notice({
        msg: "Lỗi khi tải dữ liệu từ server. Vui lòng thử lại.",
        isSuccess: false,
      })
      setListData({
        data: [],
        total: 0,
      })
    } finally {
      setLoading(false)
      console.log("Loading finished.")
    }
  }, [
    isSystemKeysLoaded, // ✅ Thêm dependency này
    pagination.CurrentPage,
    pagination.PageSize,
    textSearch,
    taxCodeSearch,
    fromDate,
    toDate,
    selectedMemberType,
    selectedStatus,
    memberTypeMap,
    statusMap,
  ])

  // ✅ useEffect thứ hai: Chỉ chạy khi SystemKeys đã tải xong
  useEffect(() => {
    loadData()
  }, [loadData])

  return (
    <SpinCustom spinning={loading}>
      <Row className="box-action sticky" gutter={12}>
        <Col span={6}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo CCCD"
            enterButton
            value={textSearch}
            onChange={handleTextSearchChange}
          />
        </Col>

        <Col span={6}>
          <InputCustom
            type="search"
            allowClear
            label="Tìm theo Mã số thuế"
            enterButton
            value={taxCodeSearch}
            onChange={handleTaxCodeSearchChange}
          />
        </Col>

        <Col span={6}>
          <DatePicker.RangePicker
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            allowClear
            value={dateRange}
            onChange={handleDateRangeChange}
            placeholder={["Từ ngày", "Đến ngày"]}
          />
        </Col>
        <Col span={3}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={handleMemberTypeChange}
            value={selectedMemberType}
            maxTagCount="responsive"
            label="Loại thành viên"
          >
            {[
              { Description: "Tất Cả", CodeValue: "0" },
              ...getListComboByKey("MEMBER_TYPE", allSystemKeys),
            ].map(option => (
              <Select.Option value={option.Description} key={option.CodeValue}>
                {option.Description}
              </Select.Option>
            ))}
          </SelectCustom>
        </Col>
        <Col span={3}>
          <SelectCustom
            allowClear
            style={{ width: "100%" }}
            onChange={handleStatusChange}
            value={selectedStatus}
            maxTagCount="responsive"
            label="Trạng thái yêu cầu"
          >
            {[
              { Description: "Tất Cả", CodeValue: "0" },
              ...getListComboByKey("USER_STATUS", allSystemKeys),
            ].map(option => (
              <Select.Option value={option.Description} key={option.CodeValue}>
                {option.Description}
              </Select.Option>
            ))}
          </SelectCustom>
        </Col>

        <Col span={24}>
          <TitleCustom className={"d-flex-sb"}>
            {
              <div
                style={{
                  position: "relative",
                  display: "flex",
                }}
              >
                <span>Đơn xin rút ({pendingRequestsCount})</span>
              </div>
            }

            <div className="d-flex-end">
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow mr-8"
                onClick={() => handleApprove()}
              >
                Chấp nhận
              </ButtonCustom>
              <ButtonCustom
                type="primary"
                className="btn-hover-shadow"
                onClick={() => handleReject()}
              >
                Từ chối
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>
      </Row>
      <TableCustom
        sticky={{ offsetHeader: -12 }}
        columns={columns}
        dataSource={listData.data || []}
        rowKey="ID"
        rowSelection={rowSelection}
        onRow={record => {
          return {
            onClick: event => {
              const selection = window.getSelection()
              const isTextSelected =
                selection && selection.toString().length > 0
              if (
                !isTextSelected &&
                !event.target.closest(".float-action__wrapper")
              ) {
                handleRowClick(record)
              }
            },
          }
        }}
        pagination={{
          current: pagination.CurrentPage,
          pageSize: pagination.PageSize,
          total: listData.total || 0,
          showSizeChanger: true,
          onChange: handleTableChange,
          onShowSizeChange: handleTableChange,
          size: "middle",
        }}
      />
      {isDetailModalVisible && (
        <ModalApprovedLeaveAssociation
          open={isDetailModalVisible}
          selectedRecord={selectedRecordDetail}
          onCancel={handleCloseDetailModal}
          onOk={() => loadData()}
          onApprove={handleApprove}
          onReject={handleReject}
          allSystemKeys={allSystemKeys}
        />
      )}
    </SpinCustom>
  )
}

export default ApprovedLeaveAssociation
